import React, { useState, useCallback, useRef, Suspense } from 'react'
import { GameHeader } from '../ui/GameHeader'
import { GameOverlay } from '../ui/GameOverlay'
import { isMobile } from '../../../../utils/functions'
import { SoccerJugglingProps } from './types'

const SoccerJugglingCore = React.lazy(() => import('./game'))

const GAME_FONT_STYLE = { fontFamily: '"Luckiest Guy", Arial, sans-serif' }

const SoccerJugglingGame: React.FC<SoccerJugglingProps> = ({
	lives = 3,
	setGameOver,
	setPointsEarned,
	brandColor = '#2d8a4e',
	skin,
	gameTitle = 'DOMINADAS',
	brandLogo,
	maxPoints,
}) => {
	const containerRef = useRef<HTMLDivElement>(null)
	const wasGamePaused = useRef(false)

	const [score, setScore] = useState(0)
	const [currentLives, setCurrentLives] = useState(lives)
	const [kicks, setKicks] = useState(0)
	const [isGameStarted, setIsGameStarted] = useState(false)
	const [isGameOver, setIsGameOver] = useState(false)
	const [isPaused, setIsPaused] = useState(false)
	const [quitGame, setQuitGame] = useState(false)
	const [gameResult, setGameResult] = useState<{
		score: number
		kicks: number
	} | null>(null)

	const isMobileDevice = isMobile()

	const startGame = useCallback(() => {
		if (!isGameStarted) {
			setIsGameStarted(true)
			setIsGameOver(false)
			setScore(0)
			setCurrentLives(lives)
			setKicks(0)
			setQuitGame(false)
			setGameResult(null)
		}
	}, [isGameStarted, lives])

	const togglePause = useCallback(() => {
		if (!isGameStarted || isGameOver) return
		setIsPaused(prev => !prev)
	}, [isGameStarted, isGameOver])

	const onPauseChange = useCallback(
		(paused: boolean) => {
			if (!isGameStarted || isGameOver) return
			setIsPaused(paused)
		},
		[isGameStarted, isGameOver]
	)

	const cancelQuit = () => {
		setQuitGame(false)
		setIsPaused(wasGamePaused.current)
	}

	const handleQuitConfirm = () => {
		setPointsEarned(score)
		setGameOver(true)
		setIsGameStarted(false)
		setIsGameOver(true)
	}

	const handleScoreUpdate = useCallback(
		(newScore: number) => {
			setScore(newScore)
			if (maxPoints && newScore >= maxPoints) {
				setIsGameOver(true)
				setPointsEarned(maxPoints)
				setGameOver(true)
			}
		},
		[maxPoints, setPointsEarned, setGameOver]
	)

	const handleLifeLost = useCallback((livesRemaining: number) => {
		setCurrentLives(livesRemaining)
	}, [])

	const handleKick = useCallback((newKicks: number) => {
		setKicks(newKicks)
	}, [])

	const handleGameOverFromPhaser = useCallback(
		(totalScore: number, totalKicks: number) => {
			setIsGameOver(true)
			setGameResult({
				score: totalScore,
				kicks: totalKicks,
			})
		},
		[]
	)

	const handleContinue = () => {
		setPointsEarned(score)
		setGameOver(true)
	}

	return (
		<div
			className="game-container game-column-narrow"
			style={{ backgroundColor: brandColor }}
			ref={containerRef}
		>
			<GameHeader
				score={score}
				lives={currentLives}
				brandColor={brandColor}
				isMobile={isMobileDevice}
				onPause={togglePause}
				isPaused={isPaused}
				onQuit={() => {
					wasGamePaused.current = isPaused
					setIsPaused(true)
					setQuitGame(true)
				}}
				showQuitButton={isGameStarted && !isGameOver}
				isQuitting={quitGame}
				customItems={
					isGameStarted && !isGameOver ? (
						<div className="game-soccer-kicks-badge">
							<span className="game-soccer-kicks-icon">⚽</span>
							<span
								className="game-soccer-kicks-value"
								style={GAME_FONT_STYLE}
							>
								{kicks}
							</span>
						</div>
					) : undefined
				}
			/>

			<div className="game-center-area">
				<div
					className="game-relative-area"
					style={{ aspectRatio: '400/600', maxHeight: '70vh' }}
				>
					{/* Start Screen */}
					{!isGameStarted && !isGameOver && (
						<GameOverlay
							type="custom"
							brandColor={brandColor}
							onAction={startGame}
							actionText="⚽ JUGAR"
							showPressToStart={false}
							customContent={
								<div className="game-start-content">
									<h1
										className="game-start-title-lg game-animate-pulse"
										style={{ ...GAME_FONT_STYLE, color: '#4ade80' }}
									>
										{gameTitle}
									</h1>
									{brandLogo && (
										<>
											<span className="game-brand-label">por:</span>
											<img
												src={brandLogo}
												alt="Brand Logo"
												className="game-brand-logo"
											/>
										</>
									)}
									<div className="game-start-instructions-lg">
										<p>⚽ Mantén el balón en el aire</p>
										<p>👆 Toca cerca del balón para patearlo</p>
										<p>🎯 Toca el centro para puntos extra</p>
										<p>❤️ {lives} vidas — ¡no dejes que caiga!</p>
									</div>
									<div
										className="game-start-footer"
										style={{ ...GAME_FONT_STYLE, color: '#fde047' }}
									>
										<p>Combo = más puntos</p>
										<p>Cerca del piso = bonus</p>
									</div>
								</div>
							}
						/>
					)}

					{/* Active Game */}
					{isGameStarted && !isGameOver && (
						<>
							<Suspense fallback={<div className="game-loading-fallback"><div className="game-loading-text game-animate-pulse">Cargando...</div></div>}>
							<SoccerJugglingCore
								onScoreUpdate={handleScoreUpdate}
								onLifeLost={handleLifeLost}
								onGameOver={handleGameOverFromPhaser}
								onKick={handleKick}
								brandColor={brandColor}
								lives={lives}
								skin={skin}
								isPaused={isPaused}
								onPauseChange={onPauseChange}
							/>
							</Suspense>
							{isPaused && !quitGame && (
								<GameOverlay
									type="pause"
									brandColor={brandColor}
									onAction={togglePause}
									actionText="▶️ CONTINUAR"
								/>
							)}
						</>
					)}

					{/* Game Over Screen */}
					{isGameOver && gameResult && (
						<GameOverlay
							type="custom"
							brandColor={brandColor}
							onAction={handleContinue}
							actionText="Continuar"
							customContent={
								<div className="game-start-content-lg">
									<h1
										className="game-start-title-lg"
										style={{ ...GAME_FONT_STYLE, color: '#facc15' }}
									>
										¡Fin del Juego!
									</h1>
									<div style={{ marginTop: '1rem' }}>
										<p
											style={{ fontSize: '2.25rem', fontWeight: 'bold', color: 'white', ...GAME_FONT_STYLE }}
										>
											{gameResult.score}
										</p>
										<p style={{ fontSize: '1.125rem', color: '#d1d5db' }}>puntos</p>
										<div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem', fontSize: '1.25rem', color: '#e5e7eb' }}>
											<span>⚽</span>
											<span style={{ fontWeight: 'bold', ...GAME_FONT_STYLE }}>
												{gameResult.kicks}
											</span>
											<span>toques</span>
										</div>
									</div>
									{gameResult.kicks >= 50 && (
										<p
											className="game-animate-pulse"
											style={{ fontSize: '1.25rem', color: '#fde047', ...GAME_FONT_STYLE }}
										>
											¡Increíble habilidad!
										</p>
									)}
									{gameResult.kicks >= 25 && gameResult.kicks < 50 && (
										<p
											style={{ fontSize: '1.25rem', color: '#86efac', ...GAME_FONT_STYLE }}
										>
											¡Muy bien!
										</p>
									)}
								</div>
							}
						/>
					)}

					{/* Quit Confirmation */}
					{quitGame && (
						<GameOverlay
							type="custom"
							title="¿Salir del Juego?"
							message={`¿Seguro? Registrarás tus puntos actuales (${score}) y terminarás la partida.`}
							brandColor={brandColor}
							customContent={
								<div className="game-quit-buttons">
									<button
										onClick={cancelQuit}
										className="game-quit-btn game-quit-btn-cancel"
									>
										Cancelar
									</button>
									<button
										onClick={handleQuitConfirm}
										className="game-quit-btn game-quit-btn-confirm"
									>
										Salir
									</button>
								</div>
							}
						/>
					)}
				</div>
			</div>
		</div>
	)
}

export default SoccerJugglingGame
