/**
 * Math utilities for 3D car racing game
 * Optimized for performance in game loop
 */

export class MathUtils {
	/**
	 * Get current timestamp
	 */
	static timestamp(): number {
		return performance.now()
	}

	/**
	 * Convert to integer with default value
	 */
	static toInt(obj: any, def: number = 0): number {
		if (obj !== null && obj !== undefined) {
			const x = parseInt(obj, 10)
			if (!isNaN(x)) return x
		}
		return def
	}

	/**
	 * Convert to float with default value
	 */
	static toFloat(obj: any, def: number = 0.0): number {
		if (obj !== null && obj !== undefined) {
			const x = parseFloat(obj)
			if (!isNaN(x)) return x
		}
		return def
	}

	/**
	 * Clamp value between min and max
	 */
	static limit(value: number, min: number, max: number): number {
		return Math.max(min, Math.min(value, max))
	}

	/**
	 * Get random integer between min and max (inclusive)
	 */
	static randomInt(min: number, max: number): number {
		return Math.round(this.interpolate(min, max, Math.random()))
	}

	/**
	 * Get random choice from array
	 */
	static randomChoice<T>(options: T[]): T {
		return options[this.randomInt(0, options.length - 1)]
	}

	/**
	 * Calculate percent remaining
	 */
	static percentRemaining(n: number, total: number): number {
		return (n % total) / total
	}

	/**
	 * Accelerate value
	 */
	static accelerate(v: number, accel: number, dt: number): number {
		return v + accel * dt
	}

	/**
	 * Linear interpolation
	 */
	static interpolate(a: number, b: number, percent: number): number {
		return a + (b - a) * percent
	}

	/**
	 * Ease in interpolation
	 */
	static easeIn(a: number, b: number, percent: number): number {
		return a + (b - a) * Math.pow(percent, 2)
	}

	/**
	 * Ease out interpolation
	 */
	static easeOut(a: number, b: number, percent: number): number {
		return a + (b - a) * (1 - Math.pow(1 - percent, 2))
	}

	/**
	 * Ease in-out interpolation
	 */
	static easeInOut(a: number, b: number, percent: number): number {
		return a + (b - a) * (-Math.cos(percent * Math.PI) / 2 + 0.5)
	}

	/**
	 * Exponential fog calculation
	 */
	static exponentialFog(distance: number, density: number): number {
		return 1 / Math.pow(Math.E, distance * distance * density)
	}

	/**
	 * Increase value with wrapping
	 */
	static increase(start: number, increment: number, max: number): number {
		let result = start + increment
		while (result >= max) result -= max
		while (result < 0) result += max
		return result
	}

	/**
	 * Check overlap between two objects
	 * Optimized version with early exit
	 */
	static overlap(
		x1: number,
		w1: number,
		x2: number,
		w2: number,
		percent: number = 1
	): boolean {
		const half1 = percent * 0.5
		const half2 = percent * 0.5
		const min1 = x1 - w1 * half1
		const max1 = x1 + w1 * half1
		const min2 = x2 - w2 * half2
		const max2 = x2 + w2 * half2
		return !(max1 < min2 || min1 > max2)
	}

	/**
	 * Project 3D point to 2D screen
	 * Optimized for performance
	 */
	static project(
		p: {
			world: { x?: number; y?: number; z?: number }
			camera: { x?: number; y?: number; z?: number }
			screen: { x?: number; y?: number; w?: number; scale?: number }
		},
		cameraX: number,
		cameraY: number,
		cameraZ: number,
		cameraDepth: number,
		width: number,
		height: number,
		roadWidth: number
	): void {
		p.camera.x = (p.world.x || 0) - cameraX
		p.camera.y = (p.world.y || 0) - cameraY
		p.camera.z = (p.world.z || 0) - cameraZ
		p.screen.scale = cameraDepth / p.camera.z
		p.screen.x = Math.round(
			width / 2 + (p.screen.scale * p.camera.x * width) / 2
		)
		p.screen.y = Math.round(
			height / 2 - (p.screen.scale * p.camera.y * height) / 2
		)
		p.screen.w = Math.round((p.screen.scale * roadWidth * width) / 2)
	}
}

// Pre-calculated values for performance
export const DEG_TO_RAD = Math.PI / 180
export const RAD_TO_DEG = 180 / Math.PI

/**
 * Fast sine approximation for non-critical calculations
 */
export function fastSin(x: number): number {
	x = x % (2 * Math.PI)
	if (x < 0) x += 2 * Math.PI

	if (x < Math.PI) {
		return (4 * x * (Math.PI - x)) / (Math.PI * Math.PI)
	} else {
		x -= Math.PI
		return (-4 * x * (Math.PI - x)) / (Math.PI * Math.PI)
	}
}

/**
 * Fast cosine approximation for non-critical calculations
 */
export function fastCos(x: number): number {
	return fastSin(x + Math.PI / 2)
}
