// Ghost Commander - controls chase/scatter mode timing

import { FPS } from '../constants'
import { GhostCommand } from '../types'
import type { Ghost } from '../core/Ghost'
import type { Energizer } from './Energizer'

/**
 * Command timing structure
 */
interface CommandTiming {
	frame: number
	command: GhostCommand
}

/**
 * Ghost Commander manages:
 * - When ghosts switch between chase and scatter modes
 * - Triggering ghost direction reversal on mode change
 */
export class GhostCommander {
	private frame: number = 0
	private command: GhostCommand = GhostCommand.SCATTER
	private level: number = 1
	private ghosts: Ghost[] = []
	private energizer: Energizer | null = null

	// Timing tables for different level ranges
	private static readonly TIMING_LEVEL_1: CommandTiming[] = [
		{ frame: 7 * FPS, command: GhostCommand.CHASE },
		{ frame: 27 * FPS, command: GhostCommand.SCATTER },
		{ frame: 34 * FPS, command: GhostCommand.CHASE },
		{ frame: 54 * FPS, command: GhostCommand.SCATTER },
		{ frame: 59 * FPS, command: GhostCommand.CHASE },
		{ frame: 79 * FPS, command: GhostCommand.SCATTER },
		{ frame: 84 * FPS, command: GhostCommand.CHASE },
	]

	private static readonly TIMING_LEVEL_2_4: CommandTiming[] = [
		{ frame: 7 * FPS, command: GhostCommand.CHASE },
		{ frame: 27 * FPS, command: GhostCommand.SCATTER },
		{ frame: 34 * FPS, command: GhostCommand.CHASE },
		{ frame: 54 * FPS, command: GhostCommand.SCATTER },
		{ frame: 59 * FPS, command: GhostCommand.CHASE },
		{ frame: 1092 * FPS, command: GhostCommand.SCATTER },
		{ frame: 1092 * FPS + 1, command: GhostCommand.CHASE },
	]

	private static readonly TIMING_LEVEL_5_PLUS: CommandTiming[] = [
		{ frame: 5 * FPS, command: GhostCommand.CHASE },
		{ frame: 25 * FPS, command: GhostCommand.SCATTER },
		{ frame: 30 * FPS, command: GhostCommand.CHASE },
		{ frame: 50 * FPS, command: GhostCommand.SCATTER },
		{ frame: 55 * FPS, command: GhostCommand.CHASE },
		{ frame: 1092 * FPS, command: GhostCommand.SCATTER },
		{ frame: 1092 * FPS + 1, command: GhostCommand.CHASE },
	]

	/**
	 * Set references to ghosts
	 */
	setGhosts(ghosts: Ghost[]): void {
		this.ghosts = ghosts
	}

	/**
	 * Set energizer reference for pause checking
	 */
	setEnergizer(energizer: Energizer): void {
		this.energizer = energizer
	}

	/**
	 * Set current level
	 */
	setLevel(level: number): void {
		this.level = level
	}

	/**
	 * Get timing table for current level
	 */
	private getTimingTable(): CommandTiming[] {
		if (this.level === 1) {
			return GhostCommander.TIMING_LEVEL_1
		} else if (this.level >= 2 && this.level <= 4) {
			return GhostCommander.TIMING_LEVEL_2_4
		}
		return GhostCommander.TIMING_LEVEL_5_PLUS
	}

	/**
	 * Check for new command at current frame
	 */
	private getNewCommand(): GhostCommand | undefined {
		const timings = this.getTimingTable()
		for (const timing of timings) {
			if (timing.frame === this.frame) {
				return timing.command
			}
		}
		return undefined
	}

	/**
	 * Reset commander state
	 */
	reset(): void {
		this.command = GhostCommand.SCATTER
		this.frame = 0
	}

	/**
	 * Update commander each frame
	 */
	update(): void {
		// Don't count frames while energizer is active
		if (this.energizer && this.energizer.isActive()) {
			return
		}

		const newCmd = this.getNewCommand()
		if (newCmd !== undefined) {
			this.command = newCmd

			// Reverse all ghosts on mode change
			for (const ghost of this.ghosts) {
				ghost.reverse()
			}
		}

		this.frame++
	}

	/**
	 * Get current command
	 */
	getCommand(): GhostCommand {
		return this.command
	}

	/**
	 * Force set command (for testing)
	 */
	setCommand(cmd: GhostCommand): void {
		this.command = cmd
	}
}
