import React from 'react'
import { triggerHaptic } from '../../../../utils/haptics'
import {
	ArrowUpIcon,
	ArrowDownIcon,
	ArrowLeftIcon,
	ArrowRightIcon,
	RotateIcon,
	GasIcon,
	BrakeIcon,
	LaunchIcon,
} from './ControlIcons'

type ControlDirection = 'up' | 'down' | 'left' | 'right' | 'action' | 'action2'

interface GameControlsProps {
	onControl: (direction: ControlDirection) => void
	onControlEnd?: (direction: ControlDirection) => void
	brandColor?: string
	showActionButton?: boolean
	actionLabel?: string
	layout?: 'dpad' | 'arrows' | 'horizontal' | 'racing' | 'tetris'
	actionIcon?: React.ReactNode
	action2Label?: string
	action2Icon?: React.ReactNode
	showRotateButton?: boolean
	onRotate?: () => void
	showLaunchButton?: boolean
	onLaunch?: () => void
}

export const GameControls: React.FC<GameControlsProps> = ({
	onControl,
	onControlEnd,
	layout = 'dpad',
	showRotateButton = false,
	onRotate,
	showLaunchButton = false,
	onLaunch,
}) => {
	const preventSelectStyles: React.CSSProperties = {
		userSelect: 'none',
		WebkitUserSelect: 'none',
		MozUserSelect: 'none',
		msUserSelect: 'none',
		touchAction: 'none',
		WebkitTouchCallout: 'none',
	}

	const handleContextMenu = (e: React.MouseEvent) => {
		e.preventDefault()
		return false
	}

	const handleTouchStart = (
		e: React.TouchEvent,
		direction: ControlDirection,
		withHaptic: 'light' | 'medium' | 'heavy' = 'light'
	) => {
		e.preventDefault()
		triggerHaptic(withHaptic)
		onControl(direction)
	}

	const handleTouchEnd = (e: React.TouchEvent, direction: ControlDirection) => {
		e.preventDefault()
		onControlEnd?.(direction)
	}

	const handleMouseDown = (direction: ControlDirection) => {
		onControl(direction)
	}

	const handleMouseUp = (direction: ControlDirection) => {
		onControlEnd?.(direction)
	}

	// Horizontal layout for Breakout
	if (layout === 'horizontal') {
		return (
			<div className="game-controls-horizontal">
				<button
					onTouchStart={e => handleTouchStart(e, 'left')}
					onTouchEnd={e => handleTouchEnd(e, 'left')}
					onMouseDown={() => handleMouseDown('left')}
					onMouseUp={() => handleMouseUp('left')}
					onContextMenu={handleContextMenu}
					className="game-controls-btn-modern game-controls-btn-paddle"
					style={preventSelectStyles}
				>
					<ArrowLeftIcon size={24} />
					<span className="game-controls-btn-label">Izquierda</span>
				</button>
				{showLaunchButton && (
					<button
						onTouchStart={e => {
							e.preventDefault()
							triggerHaptic('medium')
							onLaunch?.()
						}}
						onClick={() => onLaunch?.()}
						onContextMenu={handleContextMenu}
						className="game-controls-btn-modern game-controls-btn-green game-controls-btn-launch"
						style={preventSelectStyles}
					>
						<LaunchIcon size={24} />
						<span className="game-controls-btn-label">Lanzar</span>
					</button>
				)}
				<button
					onTouchStart={e => handleTouchStart(e, 'right')}
					onTouchEnd={e => handleTouchEnd(e, 'right')}
					onMouseDown={() => handleMouseDown('right')}
					onMouseUp={() => handleMouseUp('right')}
					onContextMenu={handleContextMenu}
					className="game-controls-btn-modern game-controls-btn-paddle"
					style={preventSelectStyles}
				>
					<ArrowRightIcon size={24} />
					<span className="game-controls-btn-label">Derecha</span>
				</button>
			</div>
		)
	}

	// Racing layout with steering on left and gas/brake on right
	if (layout === 'racing') {
		return (
			<div className="game-controls-racing">
				{/* Steering controls on the left */}
				<div className="game-controls-racing-steering">
					<button
						onTouchStart={e => handleTouchStart(e, 'left')}
						onTouchEnd={e => handleTouchEnd(e, 'left')}
						onMouseDown={() => handleMouseDown('left')}
						onMouseUp={() => handleMouseUp('left')}
						onContextMenu={handleContextMenu}
						className="game-controls-btn-modern game-controls-btn-steering"
						style={preventSelectStyles}
					>
						<ArrowLeftIcon size={28} />
					</button>
					<button
						onTouchStart={e => handleTouchStart(e, 'right')}
						onTouchEnd={e => handleTouchEnd(e, 'right')}
						onMouseDown={() => handleMouseDown('right')}
						onMouseUp={() => handleMouseUp('right')}
						onContextMenu={handleContextMenu}
						className="game-controls-btn-modern game-controls-btn-steering"
						style={preventSelectStyles}
					>
						<ArrowRightIcon size={28} />
					</button>
				</div>

				{/* Action buttons on the right */}
				<div className="game-controls-racing-actions">
					<button
						onTouchStart={e => handleTouchStart(e, 'up', 'medium')}
						onTouchEnd={e => handleTouchEnd(e, 'up')}
						onMouseDown={() => handleMouseDown('up')}
						onMouseUp={() => handleMouseUp('up')}
						onContextMenu={handleContextMenu}
						className="game-controls-btn-modern game-controls-btn-green game-controls-btn-gas"
						style={preventSelectStyles}
					>
						<GasIcon size={20} />
						<span className="game-controls-btn-label">Gas</span>
					</button>
					<button
						onTouchStart={e => handleTouchStart(e, 'down', 'medium')}
						onTouchEnd={e => handleTouchEnd(e, 'down')}
						onMouseDown={() => handleMouseDown('down')}
						onMouseUp={() => handleMouseUp('down')}
						onContextMenu={handleContextMenu}
						className="game-controls-btn-modern game-controls-btn-red game-controls-btn-brake"
						style={preventSelectStyles}
					>
						<BrakeIcon size={20} />
						<span className="game-controls-btn-label">Freno</span>
					</button>
				</div>
			</div>
		)
	}

	// Tetris layout with D-pad on left and rotate button on right
	if (layout === 'tetris' || (layout === 'arrows' && showRotateButton)) {
		return (
			<div className="game-controls-tetris">
				{/* D-pad on the left */}
				<div className="game-controls-dpad-modern">
					<button
						onTouchStart={e => handleTouchStart(e, 'up')}
						onTouchEnd={e => handleTouchEnd(e, 'up')}
						onMouseDown={() => handleMouseDown('up')}
						onMouseUp={() => handleMouseUp('up')}
						onContextMenu={handleContextMenu}
						className="game-controls-btn-modern game-controls-btn-up"
						style={preventSelectStyles}
					>
						<ArrowUpIcon size={24} />
					</button>

					<button
						onTouchStart={e => handleTouchStart(e, 'left')}
						onTouchEnd={e => handleTouchEnd(e, 'left')}
						onMouseDown={() => handleMouseDown('left')}
						onMouseUp={() => handleMouseUp('left')}
						onContextMenu={handleContextMenu}
						className="game-controls-btn-modern game-controls-btn-left"
						style={preventSelectStyles}
					>
						<ArrowLeftIcon size={24} />
					</button>

					<button
						onTouchStart={e => handleTouchStart(e, 'right')}
						onTouchEnd={e => handleTouchEnd(e, 'right')}
						onMouseDown={() => handleMouseDown('right')}
						onMouseUp={() => handleMouseUp('right')}
						onContextMenu={handleContextMenu}
						className="game-controls-btn-modern game-controls-btn-right"
						style={preventSelectStyles}
					>
						<ArrowRightIcon size={24} />
					</button>

					<button
						onTouchStart={e => handleTouchStart(e, 'down')}
						onTouchEnd={e => handleTouchEnd(e, 'down')}
						onMouseDown={() => handleMouseDown('down')}
						onMouseUp={() => handleMouseUp('down')}
						onContextMenu={handleContextMenu}
						className="game-controls-btn-modern game-controls-btn-down"
						style={preventSelectStyles}
					>
						<ArrowDownIcon size={24} />
					</button>
				</div>

				{/* Rotate button on the right */}
				<button
					onTouchStart={e => {
						e.preventDefault()
						triggerHaptic('medium')
						if (onRotate) {
							onRotate()
						} else {
							onControl('up')
						}
					}}
					onClick={() => {
						if (onRotate) {
							onRotate()
						} else {
							onControl('up')
						}
					}}
					onContextMenu={handleContextMenu}
					className="game-controls-btn-modern game-controls-btn-purple game-controls-rotate-btn"
					style={preventSelectStyles}
				>
					<RotateIcon size={32} />
					<span className="game-controls-rotate-label">Rotar</span>
				</button>
			</div>
		)
	}

	// Snake layout - centered D-pad
	if (layout === 'arrows') {
		return (
			<div className="game-controls-snake">
				<div className="game-controls-dpad-modern">
					<button
						onTouchStart={e => handleTouchStart(e, 'up')}
						onTouchEnd={e => handleTouchEnd(e, 'up')}
						onMouseDown={() => handleMouseDown('up')}
						onMouseUp={() => handleMouseUp('up')}
						onContextMenu={handleContextMenu}
						className="game-controls-btn-modern game-controls-btn-up"
						style={preventSelectStyles}
					>
						<ArrowUpIcon size={26} />
					</button>

					<button
						onTouchStart={e => handleTouchStart(e, 'left')}
						onTouchEnd={e => handleTouchEnd(e, 'left')}
						onMouseDown={() => handleMouseDown('left')}
						onMouseUp={() => handleMouseUp('left')}
						onContextMenu={handleContextMenu}
						className="game-controls-btn-modern game-controls-btn-left"
						style={preventSelectStyles}
					>
						<ArrowLeftIcon size={26} />
					</button>

					<button
						onTouchStart={e => handleTouchStart(e, 'right')}
						onTouchEnd={e => handleTouchEnd(e, 'right')}
						onMouseDown={() => handleMouseDown('right')}
						onMouseUp={() => handleMouseUp('right')}
						onContextMenu={handleContextMenu}
						className="game-controls-btn-modern game-controls-btn-right"
						style={preventSelectStyles}
					>
						<ArrowRightIcon size={26} />
					</button>

					<button
						onTouchStart={e => handleTouchStart(e, 'down')}
						onTouchEnd={e => handleTouchEnd(e, 'down')}
						onMouseDown={() => handleMouseDown('down')}
						onMouseUp={() => handleMouseUp('down')}
						onContextMenu={handleContextMenu}
						className="game-controls-btn-modern game-controls-btn-down"
						style={preventSelectStyles}
					>
						<ArrowDownIcon size={26} />
					</button>
				</div>
			</div>
		)
	}

	// D-Pad layout (default)
	return (
		<div className="game-controls-container">
			<div className="game-controls-dpad-modern">
				<button
					onTouchStart={e => handleTouchStart(e, 'up')}
					onTouchEnd={e => handleTouchEnd(e, 'up')}
					onMouseDown={() => handleMouseDown('up')}
					onMouseUp={() => handleMouseUp('up')}
					onContextMenu={handleContextMenu}
					className="game-controls-btn-modern game-controls-btn-up"
					style={preventSelectStyles}
				>
					<ArrowUpIcon size={26} />
				</button>

				<button
					onTouchStart={e => handleTouchStart(e, 'right')}
					onTouchEnd={e => handleTouchEnd(e, 'right')}
					onMouseDown={() => handleMouseDown('right')}
					onMouseUp={() => handleMouseUp('right')}
					onContextMenu={handleContextMenu}
					className="game-controls-btn-modern game-controls-btn-right"
					style={preventSelectStyles}
				>
					<ArrowRightIcon size={26} />
				</button>

				<button
					onTouchStart={e => handleTouchStart(e, 'down')}
					onTouchEnd={e => handleTouchEnd(e, 'down')}
					onMouseDown={() => handleMouseDown('down')}
					onMouseUp={() => handleMouseUp('down')}
					onContextMenu={handleContextMenu}
					className="game-controls-btn-modern game-controls-btn-down"
					style={preventSelectStyles}
				>
					<ArrowDownIcon size={26} />
				</button>

				<button
					onTouchStart={e => handleTouchStart(e, 'left')}
					onTouchEnd={e => handleTouchEnd(e, 'left')}
					onMouseDown={() => handleMouseDown('left')}
					onMouseUp={() => handleMouseUp('left')}
					onContextMenu={handleContextMenu}
					className="game-controls-btn-modern game-controls-btn-left"
					style={preventSelectStyles}
				>
					<ArrowLeftIcon size={26} />
				</button>
			</div>
		</div>
	)
}
